const { listItems } = require('./commands/list');
const { addItem } = require('./commands/add');

const commands = {
  list: listItems,
  add: addItem,
};

function run(args) {
  const cmd = args[0];
  if (!commands[cmd]) {
    return `Unknown command: ${cmd}. Available: ${Object.keys(commands).join(', ')}`;
  }
  return commands[cmd](args.slice(1));
}

module.exports = { run, commands };

