const { getStore } = require('../store');

function listItems() {
  const items = getStore();
  if (items.length === 0) return 'No items.';
  return items.map((item, i) => `${i + 1}. ${item.name} (${item.category})`).join('\n');
}

module.exports = { listItems };

files.commands/add.js:
const { getStore, saveStore } = require('../store');

function addItem(args) {
  if (args.length < 2) return 'Usage: add <name> <category>';
  const [name, category] = args;
  const items = getStore();
  items.push({ name, category });
  saveStore(items);
  return `Added: ${name} (${category})`;
}

module.exports = { addItem };

