let _store = [
  { name: 'Sword', category: 'weapon' },
  { name: 'Shield', category: 'armor' },
  { name: 'Health Potion', category: 'potion' },
  { name: 'Iron Helmet', category: 'armor' },
  { name: 'Fire Scroll', category: 'magic' },
];

function getStore() { return _store; }
function saveStore(items) { _store = items; }
function resetStore() {
  _store = [
    { name: 'Sword', category: 'weapon' },
    { name: 'Shield', category: 'armor' },
    { name: 'Health Potion', category: 'potion' },
    { name: 'Iron Helmet', category: 'armor' },
    { name: 'Fire Scroll', category: 'magic' },
  ];
}

module.exports = { getStore, saveStore, resetStore };

