const assert = require('assert');
const { run, commands } = require('../cli');
const { resetStore } = require('../store');
let passed = 0, failed = 0;
function runTest(name, fn) { resetStore(); try { fn(); passed++; console.log('PASS: ' + name); } catch(e) { failed++; console.log('FAIL: ' + name + ' — ' + e.message); } }

runTest('list works', () => { const r = run(['list']); assert.ok(r.includes('Sword')); });
runTest('add works', () => { const r = run(['add', 'Bow', 'weapon']); assert.ok(r.includes('Added')); });
runTest('search exists', () => { assert.ok(commands.search, 'search command must be registered'); });
runTest('search by name', () => { const r = run(['search', 'sword']); assert.ok(r.toLowerCase().includes('sword'), 'Should find Sword'); assert.ok(!r.toLowerCase().includes('shield'), 'Should not include Shield'); });
runTest('search by category', () => { const r = run(['search', 'armor']); assert.ok(r.includes('Shield')); assert.ok(r.includes('Iron Helmet')); assert.ok(!r.includes('Sword')); });
runTest('search no results', () => { const r = run(['search', 'zzz']); assert.ok(r.includes('No') || r.includes('no') || r.includes('0'), 'Should indicate no results'); });
runTest('search case insensitive', () => { const r = run(['search', 'SWORD']); assert.ok(r.toLowerCase().includes('sword')); });
console.log('\n' + passed + '/' + (passed+failed) + ' tests passed');
if (failed > 0) process.exit(1);
